                let target = ctx.fresh_tmp();
                out.push_str(&format!("  {} = add i64 {}, 1\n", target, cur_h));
                let spin = ctx.fresh_label("ch_recv_spin");
                let body = ctx.fresh_label("ch_recv_body");
