                // i1 before returning. Everything else just
                // returns the loaded value directly.
                if matches!(element, Type::Bool) {
                    let truncd = ctx.fresh_tmp();
                    out.push_str(&format!(
                        "  {} = icmp ne i8 {}, 0\n",
                        truncd, val
                    ));
                    return truncd;
                }
                return val;
