    out.push_str("  store i64 0, i64* %slc_nnp2\n");
    out.push_str("  br label %slc_skip_zero\n");
    out.push_str("slc_skip_zero:\n");
    out.push_str("  store i64 0, i64* %slc_nkp\n");
