        out.push_str(&format!(
            "  %len_p = getelementptr {sty}, {sty}* %xs_p, i32 0, i32 1\n",
            sty = s_ty,
        ));
        out.push_str("  %data = load i64*, i64** %data_p\n");
        out.push_str("  %n = load i64, i64* %len_p\n");
        out.push_str("  %acc_p = alloca i64\n");
        out.push_str("  store i64 %init, i64* %acc_p\n");
        out.push_str("  %i_p = alloca i64\n");
        out.push_str("  store i64 0, i64* %i_p\n");
        out.push_str("  br label %mff_loop\n");
        out.push_str("mff_loop:\n");
        out.push_str("  %i = load i64, i64* %i_p\n");
        out.push_str("  %cont = icmp slt i64 %i, %n\n");
        out.push_str("  br i1 %cont, label %mff_body, label %mff_done\n");
        out.push_str("mff_body:\n");
        out.push_str("  %slot = getelementptr i64, i64* %data, i64 %i\n");
        out.push_str("  %v = load i64, i64* %slot\n");
        out.push_str("  %mapped = call i64 %f(i64 %v)\n");
        out.push_str("  %kept = call i1 %p(i64 %mapped)\n");
        out.push_str("  br i1 %kept, label %mff_update, label %mff_skip\n");
        out.push_str("mff_update:\n");
        out.push_str("  %acc = load i64, i64* %acc_p\n");
        out.push_str("  %next = call i64 %g(i64 %acc, i64 %mapped)\n");
        out.push_str("  store i64 %next, i64* %acc_p\n");
        out.push_str("  br label %mff_skip\n");
        out.push_str("mff_skip:\n");
        out.push_str("  %i_n = add i64 %i, 1\n");
        out.push_str("  store i64 %i_n, i64* %i_p\n");
        out.push_str("  br label %mff_loop\n");
        out.push_str("mff_done:\n");
        out.push_str("  %r = load i64, i64* %acc_p\n");
        out.push_str("  ret i64 %r\n");
        out.push_str("}\n");

        // vec_map_fold (closure #316): fused map-then-fold,
        // single pass, no intermediate Vec allocation. Signature
        // `i64 (i64)*` for the mapper + `i64 (i64, i64)*` for
        // the combiner.
        let map_fold_name = format!("@intent_vec_{}__map_fold", tag);
        out.push_str(&format!(
            "define i64 {sn}({sty}* %xs_p, i64 %init, i64 (i64)* %f, i64 (i64, i64)* %g) {{\n",
            sn = map_fold_name,
            sty = s_ty,
        ));
        out.push_str(&format!(
            "  %data_p = getelementptr {sty}, {sty}* %xs_p, i32 0, i32 0\n",
            sty = s_ty,
        ));
        out.push_str(&format!(
            "  %len_p = getelementptr {sty}, {sty}* %xs_p, i32 0, i32 1\n",
            sty = s_ty,
        ));
        out.push_str("  %data = load i64*, i64** %data_p\n");
        out.push_str("  %n = load i64, i64* %len_p\n");
        out.push_str("  %acc_p = alloca i64\n");
        out.push_str("  store i64 %init, i64* %acc_p\n");
        out.push_str("  %i_p = alloca i64\n");
        out.push_str("  store i64 0, i64* %i_p\n");
        out.push_str("  br label %mf_loop\n");
        out.push_str("mf_loop:\n");
        out.push_str("  %i = load i64, i64* %i_p\n");
        out.push_str("  %cont = icmp slt i64 %i, %n\n");
        out.push_str("  br i1 %cont, label %mf_body, label %mf_done\n");
        out.push_str("mf_body:\n");
        out.push_str("  %slot = getelementptr i64, i64* %data, i64 %i\n");
        out.push_str("  %v = load i64, i64* %slot\n");
        out.push_str("  %mapped = call i64 %f(i64 %v)\n");
        out.push_str("  %acc = load i64, i64* %acc_p\n");
        out.push_str("  %next = call i64 %g(i64 %acc, i64 %mapped)\n");
        out.push_str("  store i64 %next, i64* %acc_p\n");
        out.push_str("  %i_n = add i64 %i, 1\n");
        out.push_str("  store i64 %i_n, i64* %i_p\n");
        out.push_str("  br label %mf_loop\n");
        out.push_str("mf_done:\n");
        out.push_str("  %r = load i64, i64* %acc_p\n");
        out.push_str("  ret i64 %r\n");
        out.push_str("}\n");
        // vec_chain (closure #324): concatenate two Vec<i64>s
        // into a fresh allocation of size xs->len + ys->len.
        let chain_name = format!("@intent_vec_{}__chain", tag);
        out.push_str(&format!(
            "define {sty} {sn}({sty}* %xs_p, {sty}* %ys_p) {{\n",
            sn = chain_name,
            sty = s_ty,
        ));
        out.push_str(&format!(
            "  %xs_data_p = getelementptr {sty}, {sty}* %xs_p, i32 0, i32 0\n",
            sty = s_ty,
        ));
        out.push_str(&format!(
            "  %xs_len_p = getelementptr {sty}, {sty}* %xs_p, i32 0, i32 1\n",
            sty = s_ty,
        ));
        out.push_str(&format!(
            "  %ys_data_p = getelementptr {sty}, {sty}* %ys_p, i32 0, i32 0\n",
            sty = s_ty,
        ));
        out.push_str(&format!(
            "  %ys_len_p = getelementptr {sty}, {sty}* %ys_p, i32 0, i32 1\n",
            sty = s_ty,
        ));
        out.push_str("  %xs_data = load i64*, i64** %xs_data_p\n");
        out.push_str("  %xs_len = load i64, i64* %xs_len_p\n");
        out.push_str("  %ys_data = load i64*, i64** %ys_data_p\n");
        out.push_str("  %ys_len = load i64, i64* %ys_len_p\n");
        out.push_str("  %total = add i64 %xs_len, %ys_len\n");
        out.push_str("  %is_empty = icmp eq i64 %total, 0\n");
        out.push_str("  br i1 %is_empty, label %ch_empty, label %ch_alloc\n");
        out.push_str("ch_alloc:\n");
        out.push_str("  %bytes = mul i64 %total, 8\n");
        out.push_str("  %dst_i8 = call i8* @malloc(i64 %bytes)\n");
        out.push_str("  %dst = bitcast i8* %dst_i8 to i64*\n");
        // Copy xs first.
        out.push_str("  %xs_bytes = mul i64 %xs_len, 8\n");
        out.push_str("  %xs_src_i8 = bitcast i64* %xs_data to i8*\n");
