        out.push_str("  %dd_slot_r = getelementptr i64, i64* %dd_data, i64 %dd_r\n");
        out.push_str("  %dd_slot_prev = getelementptr i64, i64* %dd_data, i64 %dd_w_m1\n");
        out.push_str("  %dd_vr = load i64, i64* %dd_slot_r\n");
