        out.push_str("  store i64 %dd_vr, i64* %dd_slot_w\n");
        out.push_str("  %dd_w_next = add i64 %dd_w, 1\n");
        out.push_str("  store i64 %dd_w_next, i64* %dd_w_p\n");
